import React from 'react';
import { SearchIcon, UserIcon } from './icons';

const Header = () => {
 return (
  <header className="fixed top-0 left-0 right-0 z-50 flex h-20 items-center bg-background px-4 md:px-8">
   <div className="flex w-full items-center justify-between gap-4 max-w-[1400px] mx-auto">
    <div className="flex items-center">
     <div className="text-xl font-bold tracking-[0.1em] text-foreground uppercase leading-tight">
      Смысл<br />Есть
     </div>
    </div>

    <div className="flex-1 max-w-xl px-12">
     <div className="relative group">
      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-secondary group-focus-within:text-foreground">
       <SearchIcon size={18} />
      </span>
      <input
       type="text"
       placeholder="Search for croissants, sourdough..."
       className="h-10 w-full rounded-full border border-transparent bg-accent px-12 text-sm outline-none ring-primary/20 transition-all focus:border-primary/30 focus:bg-background focus:ring-4"
      />
     </div>
    </div>

    <div className="flex items-center gap-2">
     <button className="flex h-10 w-10 items-center justify-center rounded-full bg-accent hover:bg-border transition-colors">
      <UserIcon size={20} />
     </button>
    </div>
   </div>
  </header>
 );
};

export default Header;
