import React from 'react';

interface ProductCardProps {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 imageColor: string;
}

const ProductCard: React.FC<ProductCardProps> = ({ name, weight, price, oldPrice, discount, imageColor }) => {
 return (
  <div className="group cursor-pointer">
   <div className={`relative aspect-square rounded-2xl overflow-hidden mb-3 bg-accent transition-transform group-hover:-translate-y-1`}>
    {/* Placeholder for product image since I can't generate now */}
    <div className={`absolute inset-0 flex items-center justify-center`}>
     <div className={`w-3/4 h-3/4 rounded-lg shadow-sm ${imageColor} opacity-80 group-hover:scale-105 transition-transform duration-500`}></div>
    </div>

    {discount && (
     <div className="absolute top-2 left-2 bg-black text-white text-[10px] font-bold px-1.5 py-0.5 rounded">
      {discount}
     </div>
    )}

    <div className="absolute bottom-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
     <button className="w-8 h-8 rounded-full bg-white shadow-md flex items-center justify-center text-primary hover:scale-110 transition-transform">
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
       <path d="M12 5v14M5 12h14" />
      </svg>
     </button>
    </div>
   </div>

   <div className="space-y-1">
    <h3 className="text-xs font-medium text-foreground leading-tight line-clamp-2">
     {name}
    </h3>
    <p className="text-[10px] text-secondary">
     {weight} • <span className="text-primary hover:underline">Special offer</span>
    </p>

    <div className="flex items-baseline gap-2 pt-1">
     <span className="text-sm font-bold">{price} ₽</span>
     {oldPrice && (
      <span className="text-[10px] text-secondary line-through">{oldPrice} ₽</span>
     )}
     <button className="ml-auto flex h-6 w-6 items-center justify-center rounded-full bg-primary/10 text-primary hover:bg-primary hover:text-white transition-colors">
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
       <path d="M12 5v14M5 12h14" />
      </svg>
     </button>
    </div>
   </div>
  </div>
 );
};

export default ProductCard;
